// Some portions generated by Codex
package org.eclipse.rdf4j.query.algebra.equivalence.internal;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertNotEquals;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.lang.reflect.Modifier;
import java.util.Map;
import java.util.Set;
import java.util.stream.Collectors;
import java.util.stream.Stream;

import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.query.algebra.Join;
import org.eclipse.rdf4j.query.algebra.QueryRoot;
import org.eclipse.rdf4j.query.algebra.QueryScopeSeed;
import org.eclipse.rdf4j.query.algebra.Service;
import org.eclipse.rdf4j.query.algebra.SingletonSet;
import org.eclipse.rdf4j.query.algebra.StatementPattern;
import org.eclipse.rdf4j.query.algebra.Var;
import org.junit.jupiter.api.Test;

class FormalTreeEncoderTest {
	private static final SimpleValueFactory VF = SimpleValueFactory.getInstance();

	@Test
	void encodesExplicitAlgebraFieldsInsteadOfDiagnosticSemanticKeys() {
		String encoded = FormalTreeEncoder.encode(new Join(new SingletonSet(), new SingletonSet()));

		assertTrue(encoded.contains("\"algebra\":{\"format\":\"rdf4j-tuple-expr\""), encoded);
		assertTrue(!encoded.contains("semanticKey"), encoded);
	}

	@Test
	void capturesBinaryAlgorithmAndQueryScopeSeed() {
		Join hashJoin = new Join(new SingletonSet(), new SingletonSet());
		hashJoin.setAlgorithm("HashJoin");
		Join mergeJoin = hashJoin.clone();
		mergeJoin.setAlgorithm("MergeJoin");
		assertNotEquals(FormalTreeEncoder.encode(hashJoin), FormalTreeEncoder.encode(mergeJoin));

		QueryRoot withoutSeed = new QueryRoot(new SingletonSet());
		QueryRoot withSeed = new QueryRoot(new SingletonSet());
		withSeed.setQueryScopeSeed(QueryScopeSeed.empty());
		assertNotEquals(FormalTreeEncoder.encode(withoutSeed), FormalTreeEncoder.encode(withSeed));
	}

	@Test
	void queryScopeSeedSchemaCoversEveryStoredField() {
		Set<String> storedFields = Stream.of(QueryScopeSeed.class.getDeclaredFields())
				.filter(field -> !Modifier.isStatic(field.getModifiers()))
				.map(field -> field.getName())
				.collect(Collectors.toSet());

		assertEquals(Set.of(
				"frameParent",
				"regionParent",
				"regionKind",
				"environmentParent",
				"environmentKind",
				"symbolName",
				"symbolFrame",
				"originFrame",
				"originRegion",
				"originEnvironment",
				"originOccurrenceStart",
				"occurrenceSymbol"), storedFields);

		QueryScopeSeed.Builder builder = QueryScopeSeed.builder();
		int frame = builder.addFrame(QueryScopeSeed.ROOT_FRAME_ID);
		int region = builder.addRegion(QueryScopeSeed.ROOT_REGION_ID, QueryScopeSeed.RegionKind.CORRELATED);
		int environment = builder.addEnvironment(
				QueryScopeSeed.ROOT_ENVIRONMENT_ID,
				QueryScopeSeed.EnvironmentKind.SERVICE);
		int symbol = builder.addSymbol("x", frame);
		int origin = builder.addOrigin(frame, region, environment);
		builder.addOccurrence(origin, symbol);
		QueryRoot root = new QueryRoot(new SingletonSet());
		root.setQueryScopeSeed(builder.build());

		String encoded = FormalTreeEncoder.encode(root);
		assertTrue(encoded.contains("\"frames\":[-1,0]"), encoded);
		assertTrue(encoded.contains("\"regions\":[{\"parent\":-1,\"kind\":\"ORDINARY\"},"
				+ "{\"parent\":0,\"kind\":\"CORRELATED\"}]"), encoded);
		assertTrue(encoded.contains("\"environments\":[{\"parent\":-1,\"kind\":\"DEFAULT\"},"
				+ "{\"parent\":0,\"kind\":\"SERVICE\"}]"), encoded);
		assertTrue(encoded.contains("\"symbols\":[{\"name\":\"x\",\"frame\":1}]"), encoded);
		assertTrue(encoded.contains("\"origins\":[{\"frame\":1,\"region\":1,\"environment\":1,"
				+ "\"occurrences\":[0]}]"), encoded);
	}

	@Test
	void capturesServiceStateThatCanDivergeFromItsVisibleChildren() {
		Service first = service("x", "first");
		Service second = service("y", "second");
		second.setArg(first.getArg().clone());
		second.setExpressionString(first.getServiceExpressionString());
		second.setPrefixDeclarations(first.getPrefixDeclarations());
		second.setBaseURI(first.getBaseURI());

		String firstEncoding = FormalTreeEncoder.encode(first);
		assertNotEquals(firstEncoding, FormalTreeEncoder.encode(second));
		assertTrue(firstEncoding.contains("\"askQueryString\":"), firstEncoding);
		assertTrue(firstEncoding.contains("\"selectQueryString\":"), firstEncoding);
	}

	private static Service service(String objectName, String body) {
		StatementPattern pattern = new StatementPattern(
				Var.of("s"),
				Var.of("p", VF.createIRI("urn:test:p")),
				Var.of(objectName));
		return new Service(
				Var.of("service", VF.createIRI("urn:test:service")),
				pattern,
				body,
				Map.of("ex", "urn:test:"),
				"urn:test:base",
				false);
	}
}
